export default {
    async fetch(request, env, ctx) {
        const json = await request.json();
        const callbackTime = json['callback_time'];

        if (!callbackTime) {
            return Response.json({
                validation_failed: false,
                custom_code_prompt: ""
            });
        }

        const appointmentDate = new Date(callbackTime);
        const pacificTime = new Date(appointmentDate.toLocaleString("en-US", { timeZone: "America/Los_Angeles" }));
        const dayOfWeek = pacificTime.getDay();
        const hour = pacificTime.getHours();
        const minutes = pacificTime.getMinutes();
        const timeInMinutes = hour * 60 + minutes;

        const businessHours = {
            0: null,
            1: { open: 300, close: 1110 },
            2: { open: 300, close: 1110 },
            3: { open: 300, close: 1110 },
            4: { open: 300, close: 1110 },
            5: { open: 300, close: 1050 },
            6: { open: 420, close: 930 }
        };

        const dayNames = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
        const requestedDay = dayNames[dayOfWeek];

        const displayHour = hour > 12 ? hour - 12 : (hour === 0 ? 12 : hour);
        const ampm = hour >= 12 ? "pm" : "am";
        const displayMinutes = minutes > 0 ? `:${minutes.toString().padStart(2, '0')}` : "";
        const requestedTime = `${displayHour}${displayMinutes}${ampm}`;

        const todayHours = businessHours[dayOfWeek];
        let validationFailed = false;
        let failureReason = "";
        let suggestion = "";

        if (todayHours === null) {
            validationFailed = true;
            failureReason = `${requestedDay} is closed`;
            suggestion = "Saturday or Monday";
        } else if (timeInMinutes < todayHours.open) {
            validationFailed = true;
            const openHour = todayHours.open / 60;
            const openDisplay = `${openHour}am`;
            failureReason = `${requestedTime} is before we open on ${requestedDay}`;
            suggestion = `earliest available on ${requestedDay} is ${openDisplay}`;
        } else if (timeInMinutes > todayHours.close) {
            validationFailed = true;
            const closeHour = Math.floor(todayHours.close / 60);
            const closeMinutes = todayHours.close % 60;
            const closeDisplay = closeHour > 12 ? `${closeHour - 12}` : `${closeHour}`;
            const closeMinutesDisplay = closeMinutes > 0 ? `:${closeMinutes.toString().padStart(2, '0')}` : "";
            const closeAmPm = closeHour >= 12 ? "pm" : "am";
            failureReason = `${requestedTime} is after we close on ${requestedDay}`;
            suggestion = `latest available on ${requestedDay} is ${closeDisplay}${closeMinutesDisplay}${closeAmPm}`;
        }

        if (!validationFailed) {
            return Response.json({
                validation_failed: false,
                custom_code_prompt: ""
            });
        }

        const customPrompt = `The user previously requested a callback at ${requestedTime} on ${requestedDay}, but this falls outside business hours - ${failureReason}.

Business hours are:
- Monday-Thursday: 5am-6:30pm
- Friday: 5am-5:30pm  
- Saturday: 7am-3:30pm
- Sunday: Closed

All times are Pacific. The ${suggestion}.

Apologize briefly for the confusion, explain that time isn't available, and offer the nearest valid alternative. Then continue with the normal confirmation flow.`;

        return Response.json({
            validation_failed: true,
            custom_code_prompt: customPrompt
        });
    }
}
